from __future__ import annotations

from collections import defaultdict, deque
from dataclasses import dataclass
import heapq


DIRS = {
    "north": (-1, 0),
    "south": (1, 0),
    "west": (0, -1),
    "east": (0, 1),
}

ORIENTS = ("N", "E", "S", "W")
TURN_DELTA = {"clockwise": 1, "counterclockwise": -1}


def add(pos: tuple[int, int], delta: tuple[int, int]) -> tuple[int, int]:
    return pos[0] + delta[0], pos[1] + delta[1]


ALL_TILES = {
    (0, 3), (0, 4), (0, 5),
    (1, 2), (1, 3), (1, 4), (1, 5),
    (2, 1), (2, 2), (2, 3), (2, 4), (2, 5),
    (3, 1), (3, 2), (3, 3), (3, 4), (3, 5),
    (4, 2), (4, 4),
    (5, 0), (5, 1), (5, 2), (5, 3), (5, 4), (5, 5),
    (6, 0), (6, 1), (6, 2), (6, 3), (6, 4), (6, 5), (6, 6),
}

ICE = {(2, 4), (5, 2), (5, 3)}
RESET = (3, 4)
RELIQUARY = (6, 6)
SUN = (2, 5)

GATE_A = (4, 4)
GATE_B = (4, 2)
AMBER_PLATE = (5, 5)
JADE_PLATE = (3, 3)

DIAL_POS = {
    "alpha": (6, 2),
    "beta": (3, 3),
    "gamma": (1, 2),
    "delta": (3, 1),
}
CONVEYORS = {
    "alpha": (5, 4),
    "beta": RESET,
    "gamma": (1, 3),
    "delta": (3, 1),
}
TARGETS = {"alpha": "E", "beta": "W", "gamma": "S", "delta": "N"}
RESET_CRATES = {"amber": (5, 1), "jade": (2, 1)}


@dataclass(frozen=True)
class State:
    player: tuple[int, int]
    amber: tuple[int, int]
    jade: tuple[int, int]
    alpha: str
    beta: str
    gamma: str
    delta: str
    sun_taken: bool
    reset_used: bool
    gate_b_latched: bool
    seal_armed: bool
    seal_progress: int

    def dial(self, name: str) -> str:
        return getattr(self, name)


INITIAL = State(
    player=(6, 0),
    amber=(5, 1),
    jade=(2, 1),
    alpha="N",
    beta="N",
    gamma="W",
    delta="E",
    sun_taken=False,
    reset_used=False,
    gate_b_latched=False,
    seal_armed=False,
    seal_progress=0,
)


def gate_a_open(state: State) -> bool:
    return state.amber == AMBER_PLATE


def gate_b_open(state: State) -> bool:
    return state.gate_b_latched or state.jade == JADE_PLATE


def passable(pos: tuple[int, int], state: State, ignore_crate: str | None = None) -> bool:
    if pos not in ALL_TILES:
        return False
    if pos == GATE_A and not gate_a_open(state):
        return False
    if pos == GATE_B and not gate_b_open(state):
        return False
    if ignore_crate != "amber" and pos == state.amber:
        return False
    if ignore_crate != "jade" and pos == state.jade:
        return False
    return True


def slide_from(
    start: tuple[int, int],
    direction: str,
    state: State,
    ignore_crate: str | None = None,
) -> tuple[int, int]:
    if start not in ICE:
        return start
    delta = DIRS[direction]
    cur = start
    while cur in ICE:
        nxt = add(cur, delta)
        if not passable(nxt, state, ignore_crate=ignore_crate):
            return cur
        cur = nxt
    return cur


def rotate(orient: str, turn: str) -> str:
    idx = ORIENTS.index(orient)
    return ORIENTS[(idx + TURN_DELTA[turn]) % 4]


def apply_conveyors(state: State) -> State:
    amber = state.amber
    jade = state.jade

    def move_crate(name: str, pos: tuple[int, int], other: tuple[int, int], orient: str) -> tuple[int, int]:
        delta = {"N": DIRS["north"], "S": DIRS["south"], "E": DIRS["east"], "W": DIRS["west"]}[orient]
        nxt = add(pos, delta)
        temp = State(
            player=state.player,
            amber=pos if name == "amber" else other,
            jade=other if name == "amber" else pos,
            alpha=state.alpha,
            beta=state.beta,
            gamma=state.gamma,
            delta=state.delta,
            sun_taken=state.sun_taken,
            reset_used=state.reset_used,
            gate_b_latched=state.gate_b_latched,
            seal_armed=state.seal_armed,
            seal_progress=state.seal_progress,
        )
        if name == "amber":
            if not passable(nxt, temp, ignore_crate="amber"):
                return pos
        else:
            if not passable(nxt, temp, ignore_crate="jade"):
                return pos
        return nxt

    if amber == CONVEYORS["alpha"]:
        amber = move_crate("amber", amber, jade, state.alpha)
    if jade == CONVEYORS["alpha"] and jade != amber:
        jade = move_crate("jade", jade, amber, state.alpha)

    if amber == CONVEYORS["beta"]:
        amber = move_crate("amber", amber, jade, state.beta)
    if jade == CONVEYORS["beta"] and jade != amber:
        jade = move_crate("jade", jade, amber, state.beta)

    if amber == CONVEYORS["gamma"]:
        amber = move_crate("amber", amber, jade, state.gamma)
    if jade == CONVEYORS["gamma"] and jade != amber:
        jade = move_crate("jade", jade, amber, state.gamma)

    if amber == CONVEYORS["delta"]:
        amber = move_crate("amber", amber, jade, state.delta)
    if jade == CONVEYORS["delta"] and jade != amber:
        jade = move_crate("jade", jade, amber, state.delta)

    latched = state.gate_b_latched or amber == JADE_PLATE or jade == JADE_PLATE
    return State(
        player=state.player,
        amber=amber,
        jade=jade,
        alpha=state.alpha,
        beta=state.beta,
        gamma=state.gamma,
        delta=state.delta,
        sun_taken=state.sun_taken,
        reset_used=state.reset_used,
        gate_b_latched=latched,
        seal_armed=state.seal_armed,
        seal_progress=state.seal_progress,
    )


def with_fields(state: State, **changes) -> State:
    data = state.__dict__.copy()
    data.update(changes)
    return State(**data)


def apply_command(state: State, command: str) -> tuple[State | None, int]:
    parts = command.split()

    if parts[0] == "move":
        direction = parts[1]
        step = add(state.player, DIRS[direction])
        if not passable(step, state):
            return None, 0
        moved = with_fields(state, player=slide_from(step, direction, state))
        return apply_post(moved, command), 0

    if parts[0] == "push":
        crate = parts[1]
        direction = parts[2]
        if crate == "amber" and direction not in {"east", "west"}:
            return None, 0
        if crate == "jade" and direction not in {"north", "south"}:
            return None, 0
        crate_pos = state.amber if crate == "amber" else state.jade
        behind = add(crate_pos, (-DIRS[direction][0], -DIRS[direction][1]))
        if state.player != behind:
            return None, 0
        step = add(crate_pos, DIRS[direction])
        if not passable(step, state, ignore_crate=crate):
            return None, 0
        final_crate = slide_from(step, direction, state, ignore_crate=crate)
        if crate == "amber":
            moved = with_fields(state, player=crate_pos, amber=final_crate)
        else:
            moved = with_fields(state, player=crate_pos, jade=final_crate)
        return apply_post(moved, command), 1

    if parts[0] == "turn":
        target = parts[1]
        turn = parts[2]
        if target == "seal":
            if not state.seal_armed or state.player != RELIQUARY:
                return None, 0
            expected = []
            for name in ("alpha", "beta", "gamma", "delta"):
                expected.append("clockwise" if state.dial(name) in {"N", "E"} else "counterclockwise")
            progress = state.seal_progress
            progress = progress + 1 if turn == expected[progress] else 0
            moved = with_fields(state, seal_progress=progress)
            return apply_post(moved, command), 0
        pos = DIAL_POS[target]
        if abs(state.player[0] - pos[0]) + abs(state.player[1] - pos[1]) > 1:
            return None, 0
        moved = with_fields(state, **{target: rotate(state.dial(target), turn)})
        return apply_post(moved, command), 0

    if parts[0] == "take":
        if parts[1] != "sun":
            return None, 0
        if state.sun_taken or state.player != SUN:
            return None, 0
        moved = apply_post(state, command)
        return with_fields(moved, sun_taken=True), 0

    if parts[0] == "drop":
        if parts[1] != "sun":
            return None, 0
        if not state.sun_taken or state.player in {state.amber, state.jade}:
            return None, 0
        if state.player != SUN:
            # The only item state the puzzle exposes is whether the sun is carried or at its floor tile.
            return None, 0
        moved = apply_post(state, command)
        return with_fields(moved, sun_taken=False), 0

    if parts[0] == "use":
        if parts[1] == "reset":
            if parts[2] != "shrine" or state.player != RESET or state.reset_used:
                return None, 0
            moved = apply_post(state, command)
            latched = moved.gate_b_latched or RESET_CRATES["amber"] == JADE_PLATE or RESET_CRATES["jade"] == JADE_PLATE
            return with_fields(
                moved,
                amber=RESET_CRATES["amber"],
                jade=RESET_CRATES["jade"],
                reset_used=True,
                gate_b_latched=latched,
                seal_progress=0,
            ), 0
        if parts[1] == "sun":
            if (
                parts[2] != "reliquary"
                or state.player != RELIQUARY
                or not state.sun_taken
                or not state.reset_used
                or any(state.dial(name) != TARGETS[name] for name in TARGETS)
            ):
                return None, 0
            moved = apply_post(state, command)
            return with_fields(moved, sun_taken=False, seal_armed=True, seal_progress=0), 0
        return None, 0

    if parts[0] == "wait":
        return apply_post(state, command), 0

    return None, 0


def apply_post(state: State, command: str) -> State:
    # Conveyor and plate/gate effects for every legal puzzle command.
    after = apply_conveyors(state)
    latched = after.gate_b_latched or after.amber == JADE_PLATE or after.jade == JADE_PLATE
    return with_fields(after, gate_b_latched=latched)


def solved(state: State) -> bool:
    return state.seal_armed and state.seal_progress == 4


def legal_commands(state: State) -> list[tuple[str, State, int]]:
    commands = [
        "drop sun",
        "move east",
        "move north",
        "move south",
        "move west",
        "push amber east",
        "push amber west",
        "push jade north",
        "push jade south",
        "take sun",
        "turn alpha clockwise",
        "turn alpha counterclockwise",
        "turn beta clockwise",
        "turn beta counterclockwise",
        "turn delta clockwise",
        "turn delta counterclockwise",
        "turn gamma clockwise",
        "turn gamma counterclockwise",
        "turn seal clockwise",
        "turn seal counterclockwise",
        "use reset shrine",
        "use sun reliquary",
        "wait",
    ]
    out = []
    for command in sorted(commands):
        nxt, push_inc = apply_command(state, command)
        if nxt is not None:
            out.append((command, nxt, push_inc))
    return out


def build_graph():
    state_to_id = {INITIAL: 0}
    states = [INITIAL]
    edges: list[list[tuple[int, str, int]]] = [[]]
    q = deque([INITIAL])

    while q:
        state = q.popleft()
        sid = state_to_id[state]
        for command, nxt, push_inc in legal_commands(state):
            nid = state_to_id.get(nxt)
            if nid is None:
                nid = len(states)
                state_to_id[nxt] = nid
                states.append(nxt)
                edges.append([])
                q.append(nxt)
            edges[sid].append((nid, command, push_inc))
    return states, edges


def scc(edges: list[list[tuple[int, str, int]]]) -> list[int]:
    n = len(edges)
    graph = [[] for _ in range(n)]
    rev = [[] for _ in range(n)]
    for u, es in enumerate(edges):
        for v, _, _ in es:
            graph[u].append(v)
            rev[v].append(u)

    order = []
    seen = [False] * n

    def dfs1(u: int):
        seen[u] = True
        for v in graph[u]:
            if not seen[v]:
                dfs1(v)
        order.append(u)

    for i in range(n):
        if not seen[i]:
            dfs1(i)

    comp = [-1] * n

    def dfs2(u: int, cid: int):
        comp[u] = cid
        for v in rev[u]:
            if comp[v] == -1:
                dfs2(v, cid)

    cid = 0
    for u in reversed(order):
        if comp[u] == -1:
            dfs2(u, cid)
            cid += 1
    return comp


def best_solution(states, edges, comp):
    pq = [(0, 0, 0, tuple(), 0)]
    best_cost = {0: (0, 0, 0, tuple())}

    while pq:
        steps, pushes, irr, path, sid = heapq.heappop(pq)
        if best_cost.get(sid) != (steps, pushes, irr, path):
            continue
        if solved(states[sid]):
            return list(path), states[sid], (steps, pushes, irr)
        for nid, command, push_inc in edges[sid]:
            irr_inc = 0 if comp[sid] == comp[nid] else 1
            new_key = (steps + 1, pushes + push_inc, irr + irr_inc, path + (command,))
            cur = best_cost.get(nid)
            if cur is None or new_key < cur:
                best_cost[nid] = new_key
                heapq.heappush(pq, (*new_key, nid))
    raise RuntimeError("no solution found")


def main():
    states, edges = build_graph()
    comp = scc(edges)
    path, final_state, cost = best_solution(states, edges, comp)
    print(f"states={len(states)}")
    print(f"cost steps={cost[0]} pushes={cost[1]} irreversible={cost[2]}")
    print(f"final={final_state}")
    for command in path:
        print(command)


if __name__ == "__main__":
    main()

